class Solution:
    def rotate(self, nums, k):
        n = len(nums)
        k %= n
        def rev(l, r):
            while l < r:
                nums[l], nums[r] = nums[r], nums[l]
                l += 1
                r -= 1
        rev(0, n - 1)
        rev(0, k - 1)
        rev(k, n - 1)

