var rotate = function(nums, k) {
    const n = nums.length;
    k %= n;
    function rev(l, r) {
        while (l < r) {
            [nums[l], nums[r]] = [nums[r], nums[l]];
            l++; r--;
        }
    }
    rev(0, n - 1);
    rev(0, k - 1);
    rev(k, n - 1);
};
